import{_ as t,o as s,c as a,ak as n}from"./chunks/framework.RPFtYYnm.js";const u=JSON.parse('{"title":"Web Pentesting","description":"","frontmatter":{},"headers":[],"relativePath":"web/index-web.md","filePath":"web/index-web.md"}'),i={name:"web/index-web.md"};function r(l,e,d,o,p,c){return s(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="web-pentesting" tabindex="-1">Web Pentesting <a class="header-anchor" href="#web-pentesting" aria-label="Permalink to “Web Pentesting”">​</a></h1><p>Les applications web sont aujourd&#39;hui la principale surface d&#39;attaque des organisations.<br> APIs, portails d&#39;authentification, interfaces d&#39;administration, applications SaaS, chaque composant web expose potentiellement des vecteurs d&#39;exploitation.<br> Le web pentesting couvre l&#39;identification et l&#39;exploitation des vulnérabilités dans ces applications.</p><h2 id="qu-est-ce-que-le-web-pentesting" tabindex="-1">Qu&#39;est-ce que le Web Pentesting ? <a class="header-anchor" href="#qu-est-ce-que-le-web-pentesting" aria-label="Permalink to “Qu&#39;est-ce que le Web Pentesting ?”">​</a></h2><p>Le web pentesting est une discipline du test d&#39;intrusion focalisée sur les applications web et leurs composants frontend, backend, APIs, bases de données et infrastructure sous-jacente. L&#39;objectif est d&#39;identifier les failles avant qu&#39;un attaquant réel ne les découvre et les exploite.</p><h3 id="difference-avec-le-pentest-reseau" tabindex="-1">Différence avec le pentest réseau <a class="header-anchor" href="#difference-avec-le-pentest-reseau" aria-label="Permalink to “Différence avec le pentest réseau”">​</a></h3><table tabindex="0"><thead><tr><th>Critère</th><th>Web Pentesting</th><th>Network Pentesting</th></tr></thead><tbody><tr><td>Cible</td><td>Applications web, APIs</td><td>Infrastructure réseau</td></tr><tr><td>Protocoles</td><td>HTTP, HTTPS, WebSocket</td><td>TCP/IP, SMB, RDP, etc.</td></tr><tr><td>Outils</td><td>Burp Suite, SQLMap, ffuf</td><td>Nmap, Metasploit, NXC</td></tr><tr><td>Compétences</td><td>Dev web, logique applicative</td><td>Réseau, protocoles, AD</td></tr><tr><td>Failles</td><td>OWASP Top 10</td><td>CVE, mauvaises configs</td></tr></tbody></table><h2 id="owasp-top-10-2025" tabindex="-1">OWASP Top 10 2025 <a class="header-anchor" href="#owasp-top-10-2025" aria-label="Permalink to “OWASP Top 10 2025”">​</a></h2><p>Le référentiel OWASP Top 10 liste les vulnérabilités web les plus critiques et les plus fréquentes.</p><table tabindex="0"><thead><tr><th>Rang</th><th>Catégorie</th><th>Description</th></tr></thead><tbody><tr><td>A01</td><td>Broken Access Control</td><td>Contrôles d&#39;accès insuffisants</td></tr><tr><td>A02</td><td>Cryptographic Failures</td><td>Chiffrement faible ou absent</td></tr><tr><td>A03</td><td>Injection</td><td>SQLi, XSS, Command Injection</td></tr><tr><td>A04</td><td>Insecure Design</td><td>Défauts de conception</td></tr><tr><td>A05</td><td>Security Misconfiguration</td><td>Mauvaises configurations</td></tr><tr><td>A06</td><td>Vulnerable Components</td><td>Composants obsolètes ou vulnérables</td></tr><tr><td>A07</td><td>Authentication Failures</td><td>Authentification défaillante</td></tr><tr><td>A08</td><td>Software &amp; Data Integrity</td><td>Intégrité des données non vérifiée</td></tr><tr><td>A09</td><td>Logging Failures</td><td>Journalisation insuffisante</td></tr><tr><td>A10</td><td>SSRF</td><td>Requêtes forgées côté serveur</td></tr></tbody></table><h2 id="surface-d-attaque-web" tabindex="-1">Surface d&#39;Attaque Web <a class="header-anchor" href="#surface-d-attaque-web" aria-label="Permalink to “Surface d&#39;Attaque Web”">​</a></h2><h3 id="composants-a-tester" tabindex="-1">Composants à tester <a class="header-anchor" href="#composants-a-tester" aria-label="Permalink to “Composants à tester”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span> Application Web</span></span>
<span class="line"><span>     ├── Frontend</span></span>
<span class="line"><span>     │   ├── JavaScript (logique côté client)</span></span>
<span class="line"><span>     │   ├── HTML / CSS (injection)</span></span>
<span class="line"><span>     │   └── Cookies / Storage (session)</span></span>
<span class="line"><span>     ├── Backend</span></span>
<span class="line"><span>     │   ├── Langage (PHP, Python, Node.js, Java)</span></span>
<span class="line"><span>     │   ├── Framework (Laravel, Django, Express)</span></span>
<span class="line"><span>     │   └── Logique métier</span></span>
<span class="line"><span>     ├── API</span></span>
<span class="line"><span>     │   ├── REST</span></span>
<span class="line"><span>     │   ├── GraphQL</span></span>
<span class="line"><span>     │   └── SOAP</span></span>
<span class="line"><span>     ├── Base de données</span></span>
<span class="line"><span>     │   ├── SQL (MySQL, PostgreSQL, MSSQL)</span></span>
<span class="line"><span>     │   └── NoSQL (MongoDB, Redis)</span></span>
<span class="line"><span>     └── Infrastructure</span></span>
<span class="line"><span>         ├── Serveur web (Apache, Nginx, IIS)</span></span>
<span class="line"><span>         ├── CDN / WAF</span></span>
<span class="line"><span>         └── Cloud (AWS, Azure, GCP)</span></span></code></pre></div><h3 id="points-d-entree-courants" tabindex="-1">Points d&#39;entrée courants <a class="header-anchor" href="#points-d-entree-courants" aria-label="Permalink to “Points d&#39;entrée courants”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span> Paramètres GET / POST</span></span>
<span class="line"><span> Headers HTTP (User-Agent, Referer, X-Forwarded-For)</span></span>
<span class="line"><span> Cookies et tokens de session</span></span>
<span class="line"><span> Fichiers uploadés</span></span>
<span class="line"><span> Endpoints API</span></span>
<span class="line"><span> Formulaires d&#39;authentification</span></span>
<span class="line"><span> Fonctions de recherche</span></span>
<span class="line"><span> Paramètres de pagination</span></span>
<span class="line"><span> Redirections et callbacks</span></span>
<span class="line"><span> WebSockets</span></span></code></pre></div><h2 id="methodologie-web-pentesting" tabindex="-1">Méthodologie Web Pentesting <a class="header-anchor" href="#methodologie-web-pentesting" aria-label="Permalink to “Méthodologie Web Pentesting”">​</a></h2><h3 id="workflow-general" tabindex="-1">Workflow général <a class="header-anchor" href="#workflow-general" aria-label="Permalink to “Workflow général”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span> 1. Reconnaissance &amp; Fingerprinting</span></span>
<span class="line"><span>    └── Technologies, CMS, WAF, sous-domaines</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 2. Enumération</span></span>
<span class="line"><span>    └── Répertoires, fichiers, endpoints, paramètres</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 3. Analyse de la surface d&#39;attaque</span></span>
<span class="line"><span>    └── Cartographier tous les points d&#39;entrée</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 4. Tests d&#39;authentification</span></span>
<span class="line"><span>    └── Bruteforce, enumération users, session management</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 5. Tests d&#39;autorisation</span></span>
<span class="line"><span>    └── IDOR, BOLA, privilege escalation</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 6. Tests d&#39;injection</span></span>
<span class="line"><span>    └── SQLi, XSS, Command Injection, SSTI, LFI/RFI</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 7. Tests de logique métier</span></span>
<span class="line"><span>    └── Contournement de paiements, conditions de course</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 8. Tests API</span></span>
<span class="line"><span>    └── REST, GraphQL, endpoints non documentés</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 9. Exploitation &amp; Preuves</span></span>
<span class="line"><span>    └── PoC, screenshots, impact démontré</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 10. Reporting</span></span>
<span class="line"><span>     └── Findings, sévérité, recommandations</span></span></code></pre></div><h2 id="outils-essentiels" tabindex="-1">Outils Essentiels <a class="header-anchor" href="#outils-essentiels" aria-label="Permalink to “Outils Essentiels”">​</a></h2><h3 id="burp-suite" tabindex="-1">Burp Suite <a class="header-anchor" href="#burp-suite" aria-label="Permalink to “Burp Suite”">​</a></h3><p>L&#39;outil incontournable du web pentesting proxy HTTP, scanner, intruder, repeater.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span> Proxy     → Intercepter et modifier les requêtes HTTP</span></span>
<span class="line"><span> Repeater  → Rejouer et modifier des requêtes manuellement</span></span>
<span class="line"><span> Intruder  → Automatiser des attaques (bruteforce, fuzzing)</span></span>
<span class="line"><span> Scanner   → Scanner automatique de vulnérabilités (Pro)</span></span>
<span class="line"><span> Decoder   → Encoder / décoder (Base64, URL, HTML, etc.)</span></span>
<span class="line"><span> Comparer  → Comparer deux réponses</span></span>
<span class="line"><span> Sequencer → Analyser l&#39;entropie des tokens</span></span></code></pre></div><h3 id="outils-par-categorie" tabindex="-1">Outils par catégorie <a class="header-anchor" href="#outils-par-categorie" aria-label="Permalink to “Outils par catégorie”">​</a></h3><table tabindex="0"><thead><tr><th>Catégorie</th><th>Outils</th></tr></thead><tbody><tr><td>Proxy / Interception</td><td>Burp Suite, OWASP ZAP, mitmproxy</td></tr><tr><td>Enumération</td><td>gobuster, ffuf, dirsearch, feroxbuster</td></tr><tr><td>SQLi</td><td>sqlmap, ghauri</td></tr><tr><td>XSS</td><td>XSStrike, dalfox</td></tr><tr><td>Fuzzing</td><td>ffuf, wfuzz, Burp Intruder</td></tr><tr><td>Fingerprinting</td><td>whatweb, wappalyzer, wafw00f</td></tr><tr><td>CMS</td><td>wpscan, droopescan, joomscan</td></tr><tr><td>SSRF</td><td>ssrfmap, Burp Collaborator</td></tr><tr><td>JWT</td><td>jwt_tool, hashcat</td></tr><tr><td>Recon</td><td>amass, subfinder, theHarvester</td></tr></tbody></table><h2 id="vulnerabilites-couvertes" tabindex="-1">Vulnérabilités Couvertes <a class="header-anchor" href="#vulnerabilites-couvertes" aria-label="Permalink to “Vulnérabilités Couvertes”">​</a></h2><p>Cette section documente les techniques d&#39;exploitation des vulnérabilités web les plus courantes en pentest.</p><table tabindex="0"><thead><tr><th>Vulnérabilité</th><th>Description</th><th>Impact</th></tr></thead><tbody><tr><td>SQL Injection</td><td>Injection de code SQL</td><td>Dump DB, RCE, Auth bypass</td></tr><tr><td>XSS</td><td>Injection de scripts</td><td>Vol session, phishing, keylogger</td></tr><tr><td>LFI / RFI</td><td>Inclusion de fichiers</td><td>Lecture fichiers, RCE</td></tr><tr><td>SSRF</td><td>Requêtes forgées serveur</td><td>Accès services internes</td></tr><tr><td>Command Injection</td><td>Injection de commandes OS</td><td>RCE</td></tr><tr><td>Path Traversal</td><td>Navigation hors répertoire</td><td>Lecture fichiers sensibles</td></tr><tr><td>IDOR</td><td>Référence directe non sécurisée</td><td>Accès données non autorisé</td></tr><tr><td>File Upload</td><td>Upload de fichiers malveillants</td><td>RCE, webshell</td></tr><tr><td>JWT Attacks</td><td>Manipulation de tokens</td><td>Auth bypass, privilege escalation</td></tr><tr><td>SSTI</td><td>Injection dans les templates</td><td>RCE</td></tr><tr><td>XXE</td><td>Injection XML externe</td><td>SSRF, LFI, RCE</td></tr><tr><td>CORS</td><td>Mauvaise configuration CORS</td><td>Vol de données cross-origin</td></tr><tr><td>Clickjacking</td><td>Superposition d&#39;iframes</td><td>Actions non voulues</td></tr><tr><td>Open Redirect</td><td>Redirection non contrôlée</td><td>Phishing</td></tr></tbody></table><h2 id="environnements-de-lab" tabindex="-1">Environnements de Lab <a class="header-anchor" href="#environnements-de-lab" aria-label="Permalink to “Environnements de Lab”">​</a></h2><p>Pour pratiquer légalement le web pentesting :</p><table tabindex="0"><thead><tr><th>Lab</th><th>Description</th><th>Lien</th></tr></thead><tbody><tr><td>DVWA</td><td>Damn Vulnerable Web App</td><td><a href="https://dvwa.co.uk/" target="_blank" rel="noreferrer">dvwa.co.uk</a></td></tr><tr><td>HackTheBox</td><td>Machines et challenges web</td><td><a href="https://hackthebox.com/" target="_blank" rel="noreferrer">hackthebox.com</a></td></tr><tr><td>TryHackMe</td><td>Parcours guidés web</td><td><a href="https://tryhackme.com/" target="_blank" rel="noreferrer">tryhackme.com</a></td></tr><tr><td>PortSwigger Web Academy</td><td>Labs OWASP officiel Burp</td><td><a href="https://portswigger.net/web-security" target="_blank" rel="noreferrer">portswigger.net</a></td></tr><tr><td>OWASP WebGoat</td><td>App vulnérable éducative</td><td><a href="https://owasp.org/www-project-webgoat/" target="_blank" rel="noreferrer">owasp.org</a></td></tr><tr><td>PentesterLab</td><td>Exercices web progressifs</td><td><a href="https://pentesterlab.com/" target="_blank" rel="noreferrer">pentesterlab.com</a></td></tr><tr><td>VulnHub</td><td>VMs vulnérables</td><td><a href="https://vulnhub.com/" target="_blank" rel="noreferrer">vulnhub.com</a></td></tr></tbody></table><h2 id="checklist-reconnaissance-web" tabindex="-1">Checklist Reconnaissance Web <a class="header-anchor" href="#checklist-reconnaissance-web" aria-label="Permalink to “Checklist Reconnaissance Web”">​</a></h2><details class="details custom-block"><summary>Checklist</summary><ul><li>Technologies identifiées (whatweb, wappalyzer)</li><li>WAF détecté (wafw00f)</li><li>Sous-domaines énumérés</li><li>Répertoires et fichiers cachés découverts</li><li>Fichiers sensibles vérifiés (robots.txt, sitemap.xml, .git, .env)</li><li>Headers HTTP analysés</li><li>Cookies inspectés (Secure, HttpOnly, SameSite)</li><li>CMS identifié et version notée</li><li>Formulaires et paramètres cartographiés</li><li>Endpoints API découverts</li><li>Méthodes HTTP testées (OPTIONS, PUT, DELETE)</li><li>Erreurs et messages d&#39;information collectés</li></ul></details><div class="info custom-block"><p class="custom-block-title">Tips</p><ul><li>Toujours commencer par <strong>cartographier</strong> l&#39;intégralité de l&#39;application avant d&#39;exploiter</li><li>Burp Suite est indispensable activer le proxy dès le début et tout intercepter</li><li>Les fichiers <code>.git</code>, <code>.env</code>, <code>backup.zip</code> exposés sont des jackpots en reconnaissance</li><li>Tester <strong>chaque paramètre</strong> les développeurs oublient souvent des paramètres non documentés</li><li>La logique métier est souvent la vulnérabilité la plus impactante et la plus difficile à trouver automatiquement</li><li>Ne jamais sous-estimer les <strong>headers HTTP</strong> <code>X-Forwarded-For</code>, <code>Origin</code>, <code>Referer</code> sont souvent injectables</li><li>Les APIs REST et GraphQL ont souvent des endpoints non documentés accessibles via fuzzing</li></ul></div><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to “Notes”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span> # Notes terrain</span></span></code></pre></div><h2 id="ressources" tabindex="-1">Ressources <a class="header-anchor" href="#ressources" aria-label="Permalink to “Ressources”">​</a></h2><ul><li><a href="https://owasp.org/www-top-10/" target="_blank" rel="noreferrer">OWASP Top 10</a></li><li><a href="https://portswigger.net/web-security" target="_blank" rel="noreferrer">PortSwigger Web Security Academy</a></li><li><a href="https://book.hacktricks.xyz/network-services-pentesting/pentesting-web" target="_blank" rel="noreferrer">HackTricks Web Pentesting</a></li><li><a href="https://github.com/swisskyrepo/PayloadsAllTheThings" target="_blank" rel="noreferrer">PayloadsAllTheThings Web</a></li><li><a href="https://owasp.org/www-project-web-security-testing-guide/" target="_blank" rel="noreferrer">OWASP Testing Guide</a></li><li><a href="https://github.com/jhaddix/tbhm" target="_blank" rel="noreferrer">Bug Bounty Methodology</a></li></ul><div class="page-footer"><p><span><img src="https://img.shields.io/github/last-commit/Hackthus/The-Hackers-237?label=Last%20updated&amp;style=flat-square&amp;color=gray" alt="Last updated"></span></p><p><span><a href="https://github.com/Hackthus/The-Hackers-237/edit/main/docs/web/index.md" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/%E2%9C%8F%EF%B8%8F%20Edit%20this%20page-GitHub-black?style=flat-square&amp;logo=github" alt="Edit this page on GitHub"></a></span></p></div>`,37)])])}const b=t(i,[["render",r]]);export{u as __pageData,b as default};
